function r2Client() {
  if (!R2_ACCOUNT_ID || !R2_ACCESS_KEY_ID || !R2_SECRET_ACCESS_KEY) return null;
  return new S3Client({
    region: "auto",
    endpoint: `https://${R2_ACCOUNT_ID}.r2.cloudflarestorage.com`,
    credentials: {
      accessKeyId: R2_ACCESS_KEY_ID,
      secretAccessKey: R2_SECRET_ACCESS_KEY
    }
  });
}

function publicUrl(key) {
  return `${String(R2_PUBLIC_BASE_URL).replace(/\/$/, "")}/${key}`;
}

function esc(value) {
  return String(value || "")
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;");
}

function clean(value, fallback = "") {
  return String(value || fallback).replace(/\s+/g, " ").trim();
}

function hardLimit(value, max = 160) {
  const text = clean(value);
  if (text.length <= max) return text;
  return text.slice(0, max - 1).replace(/\s+\S*$/, "") + "…";
}

function wrapWords(text, maxChars = 24, maxLines = 8) {
  const words = clean(text).split(" ");
  const lines = [];
  let line = "";

  for (const word of words) {
    const next = line ? `${line} ${word}` : word;
    if (next.length > maxChars && line) {
      lines.push(line);
      line = word;
    } else {
      line = next;
    }
    if (lines.length >= maxLines) break;
  }

  if (line && lines.length < maxLines) lines.push(line);
  return lines;
}

function textBlock({ text, x, y, fontSize = 60, fill = "#FFFFFF", weight = 900, maxChars = 24, maxLines = 6, anchor = "start", lineHeight = 1.05, stroke = true }) {
  const lines = wrapWords(text, maxChars, maxLines);
  return lines.map((line, i) => `<text x="${x}" y="${y + i * fontSize * lineHeight}" text-anchor="${anchor}" font-family="Arial Black, Impact, Arial, sans-serif" font-size="${fontSize}" font-weight="${weight}" fill="${fill}" ${stroke ? 'stroke="#000" stroke-width="2" paint-order="stroke"' : ""}>${esc(line)}</text>`).join("\n");
}

