async function fetchRecord(recordId) {
  if (!AIRTABLE_TOKEN) {
    throw new Error("Missing AIRTABLE_TOKEN on Render. Add AIRTABLE_PERSONAL_ACCESS_TOKEN or AIRTABLE_TOKEN in Render environment.");
  }

  const response = await fetch(`${AIRTABLE_TABLE_URL}/${recordId}`, {
    headers: { Authorization: `Bearer ${AIRTABLE_TOKEN}` }
  });

  if (!response.ok) {
    throw new Error(`Airtable fetch failed: ${response.status} ${await response.text()}`);
  }

  return await response.json();
}

async function patchRecord(recordId, fields) {
  await fetch(`${AIRTABLE_TABLE_URL}/${recordId}`, {
    method: "PATCH",
    headers: {
      Authorization: `Bearer ${AIRTABLE_TOKEN}`,
      "Content-Type": "application/json"
    },
    body: JSON.stringify({ fields, typecast: true })
  });
}

async function svgToPng(svg, outPath) {
  await sharp(Buffer.from(svg)).png().toFile(outPath);
}

async function uploadFile(key, filePath, contentType) {
  const client = r2Client();
  if (!client) throw new Error("R2 not configured.");
  const body = await fs.readFile(filePath);
  await client.send(new PutObjectCommand({
    Bucket: R2_BUCKET,
    Key: key,
    Body: body,
    ContentType: contentType
  }));
}

async function r2Exists(key) {
  const client = r2Client();
  if (!client) return false;
  try {
    await client.send(new HeadObjectCommand({ Bucket: R2_BUCKET, Key: key }));
    return true;
  } catch (e) {
    return false;
  }
}

async function renderPromptPack(recordId) {
  const keyPrefix = `${R2_PREFIX}/${recordId}`;
  const htmlKey = `${keyPrefix}/carousel.html`;
  const htmlUrl = publicUrl(htmlKey);

  const attempt = {
    recordId,
    startedAt: new Date().toISOString(),
    keyPrefix,
    htmlKey,
    stage: "started"
  };

  renderAttempts.set(recordId, attempt);

  const tmpDir = await fs.mkdtemp(path.join(os.tmpdir(), `prompt-pack-${recordId}-`));

  try {
    attempt.stage = "fetch_airtable_record";
    const record = await fetchRecord(recordId);

    attempt.stage = "parse_prompt_pack";
    const pack = parsePack(record.fields || {});

    attempt.stage = "build_slide_svgs";
    const svgs = slideSvgs(pack);

    const slideUrls = [];

    for (let i = 0; i < svgs.length; i++) {
      attempt.stage = `render_png_slide_${i + 1}`;
      const pngPath = path.join(tmpDir, `slide-${i + 1}.png`);
      await svgToPng(svgs[i], pngPath);

      const slideKey = `${keyPrefix}/slide-${i + 1}.png`;

      attempt.stage = `upload_png_slide_${i + 1}`;
      await uploadFile(slideKey, pngPath, "image/png");

      slideUrls.push(publicUrl(slideKey));
    }

    attempt.stage = "build_html_carousel";

    const html = `<!doctype html>
<html>
<head>
<meta charset="utf-8"/>
<meta name="viewport" content="width=device-width,initial-scale=1"/>
<title>${esc(pack.theme || "AI Tool Logbook Prompt Pack")}</title>
<style>
  body{margin:0;background:#050505;color:white;font-family:Arial,Helvetica,sans-serif;}
  .wrap{max-width:1080px;margin:0 auto;padding:20px;}
  h1{font-size:34px;line-height:1.05;margin:14px 0 18px;}
  .slide{width:100%;border-radius:18px;margin:0 0 18px;display:block;box-shadow:0 10px 35px rgba(255,122,0,.25);}
  .caption{background:#111;border:2px solid #ff7a00;border-radius:16px;padding:18px;margin:18px 0;font-size:20px;line-height:1.35;white-space:pre-wrap;}
  .note{color:#ff9f1a;font-weight:800;font-size:18px;margin:20px 0;}
</style>
</head>
<body>
<div class="wrap">
  <h1>${esc(stripBreaking(pack.breakingHook) || pack.theme)}</h1>
  ${slideUrls.map((url, idx) => `<img class="slide" src="${url}" alt="Slide ${idx + 1}"/>`).join("\n")}
  <div class="caption">${esc(pack.caption || "")}</div>
  <div class="caption">${esc(pack.firstComment || "")}</div>
  <div class="note">AI Tool Logbook Prompt Pack Carousel</div>
</div>
</body>
</html>`;

    const htmlPath = path.join(tmpDir, "carousel.html");
    await fs.writeFile(htmlPath, html, "utf-8");

    attempt.stage = "upload_html_carousel";
    await uploadFile(htmlKey, htmlPath, "text/html");

    await patchRecord(recordId, {
      "AITL FFmpeg Render URL": htmlUrl,
      "Render URL": htmlUrl,
      "Renderer ID": "Prompt Pack Carousel Renderer V8 No Face",
      "Render Error": "",
      "AITL Carousel Status": "prompt_pack_ready",
      "AITL Carousel Notes": `Prompt Pack V8 no-face carousel rendered. Slide URLs: ${slideUrls.join(" ")} ${new Date().toISOString()}`
    });

    const job = {
      ok: true,
      recordId,
      status: "ready",
      videoUrl: htmlUrl,
      carouselUrl: htmlUrl,
      slideUrls,
      updatedAt: new Date().toISOString()
    };

    jobs.set(recordId, job);
    return job;
  } catch (error) {
    const failure = {
      ok: false,
      recordId,
      status: "failed",
      error: error.message,
      stack: String(error.stack || "").slice(0, 4000),
      stage: renderAttempts.get(recordId)?.stage || "unknown",
      attempt: renderAttempts.get(recordId) || null,
      updatedAt: new Date().toISOString()
    };

    renderErrors.set(recordId, failure);
    jobs.set(recordId, failure);

    try {
      await patchRecord(recordId, {
        "Render Error": `${failure.stage}: ${error.message}`,
        "AITL Carousel Notes": `Prompt Pack V8 render failed at ${failure.stage}. ${new Date().toISOString()}`
      });
    } catch (e) {}

    throw error;
  } finally {
    await fs.rm(tmpDir, { recursive: true, force: true });
  }
}

app.get("/health", (req, res) => {
  res.json({
    ok: true,
    service: "AI Tool Logbook Prompt Pack Renderer",
    storage: "r2",
    r2Configured: !!r2Client(),
    airtableConfigured: !!AIRTABLE_TOKEN,
    bucket: R2_BUCKET,
    layout: "prompt-pack-v8-no-face-carousel",
    video: "carousel-png-html-no-ffmpeg",
    dimensions: "1080x1350 carousel slides",
    r2KeyPrefix: R2_PREFIX,
    renderMode: "prompt-pack-v8-prompt-pack-only-no-face",
    queueRunning: false,
    queuedJobs: 0,
    ffmpegPath: false,
    timestamp: new Date().toISOString()
  });
});

app.post("/render/aitl-prompt-pack-video", async (req, res) => {
  const key = req.headers["x-render-key"];
  if (key !== SERVER_RENDER_KEY) {
    return res.status(401).json({ ok: false, error: "Unauthorized" });
  }

  const recordId = req.body?.recordId;
  if (!recordId) {
    return res.status(400).json({ ok: false, error: "Missing recordId" });
  }

  const htmlKey = `${R2_PREFIX}/${recordId}/carousel.html`;
  const htmlUrl = publicUrl(htmlKey);

  if (!req.body?.force && await r2Exists(htmlKey)) {
    const ready = { ok: true, recordId, status: "ready", videoUrl: htmlUrl, carouselUrl: htmlUrl, storage: "r2" };
    jobs.set(recordId, ready);
    return res.json(ready);
  }

  jobs.set(recordId, {
    ok: true,
    recordId,
    status: "rendering",
    videoUrl: htmlUrl,
    createdAt: new Date().toISOString()
  });

  try {
    const job = await renderPromptPack(recordId);

    return res.json({
      ok: true,
      renderId: `aitl_prompt_pack_${recordId}`,
      status: "ready",
      videoUrl: job.videoUrl,
      carouselUrl: job.carouselUrl,
      slideUrls: job.slideUrls,
      storage: "r2",
      attempt: renderAttempts.get(recordId) || null,
      notes: "Prompt Pack V8 no-face carousel render completed."
    });
  } catch (error) {
    const failure = jobs.get(recordId) || {
      ok: false,
      recordId,
      status: "failed",
      error: error.message,
      videoUrl: htmlUrl
    };

    return res.status(500).json(failure);
  }
});

app.get("/render/aitl-prompt-pack-video/status/:recordId", async (req, res) => {
  const recordId = req.params.recordId;
  const htmlKey = `${R2_PREFIX}/${recordId}/carousel.html`;
  const htmlUrl = publicUrl(htmlKey);

  if (await r2Exists(htmlKey)) {
    return res.json({ ok: true, recordId, status: "ready", videoUrl: htmlUrl, carouselUrl: htmlUrl });
  }

  const job = jobs.get(recordId);
  if (job) {
    return res.json(job);
  }

  const failure = renderErrors.get(recordId);
  if (failure) {
    return res.json(failure);
  }

  return res.json({
    ok: true,
    recordId,
    status: "missing",
    videoUrl: htmlUrl,
    lastAttempt: renderAttempts.get(recordId) || null,
    notes: "No queued job, no finished job in memory, no remembered failure, and no R2 object found."
  });
});

app.get("/debug/prompt-pack/:recordId", (req, res) => {
  const recordId = req.params.recordId;
  res.json({
    ok: true,
    recordId,
    job: jobs.get(recordId) || null,
    error: renderErrors.get(recordId) || null,
    attempt: renderAttempts.get(recordId) || null,
    allJobs: [...jobs.entries()].map(([id, job]) => ({ id, status: job.status, error: job.error || null, stage: job.stage || null }))
  });
});

app.listen(PORT, () => {
  console.log(`AI Tool Logbook Prompt Pack Renderer V8 no-face running on port ${PORT}`);
});
